class Solution:
    def myFunc(self, n: int) -> float:
        import math
        sqrt = math.sqrt(n)
        return round(sqrt * 2) / 2 if sqrt % 1 != 0 else math.floor(sqrt)


# test cases
if __name__ == '__main__':
    print(Solution().myFunc(9))
    print(Solution().myFunc(10))
    print(Solution().myFunc(100))
    print(Solution().myFunc(101))

