#include <iostream>
#include <cmath>
using namespace std;

class Solution {
public:
    double myFunc(int n) {
        double sqrt = sqrt(n);
        return round(sqrt * 2) / 2.0f;
    }
};

int main() {
    Solution solution;
    cout << solution.myFunc(9) << endl;
    cout << solution.myFunc(10) << endl;
    cout << solution.myFunc(100) << endl;
    cout << solution.myFunc(101) << endl;
    return 0;
}
